import { Component } from '@angular/core';
import { ViewController, LoadingController, AlertController, NavParams } from 'ionic-angular';
// Forms
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
// Providers
import { BankService } from '../../../../providers/logged-in/bank.service';
// Models
import { Bank } from '../../../../models/bank';

@Component({
  selector: 'page-bank-form',
  templateUrl: 'bank-form.html'
})
export class BankFormPage {

  public model: Bank;
  public operation:string;

  public form: FormGroup;

  constructor(
    params: NavParams,
    public bankService: BankService,
    private _fb: FormBuilder,
    private _viewCtrl: ViewController,
    private _loadingCtrl: LoadingController,
    private _alertCtrl: AlertController
  ){
    // Load the passed model if available
    this.model = params.get('model');

    // Init Form
    if(!this.model.bank_id){ // Show Create Form
      this.operation = "Create";
      this.form = this._fb.group({
        name: ["", Validators.required],
        swift_code: ["", Validators.required],
        address: ["", Validators.required],
        type: ["", Validators.required]
      });
    }else{ // Show Update Form
      this.operation = "Update";
      this.form = this._fb.group({
        name: [this.model.bank_name, Validators.required],
        swift_code: [this.model.bank_swift_code, Validators.required],
        address: [this.model.bank_address, Validators.required],
        type: [this.model.bank_transfer_type, Validators.required]
      });
    }
  }

  /**
   * Update Model Data based on Form Input
   */
  updateModelDataFromForm(){
    this.model.bank_name = this.form.value.name,
    this.model.bank_swift_code = this.form.value.swift_code,
    this.model.bank_address = this.form.value.address
    this.model.bank_transfer_type = this.form.value.type
  }

  /**
   * Close the page
   */
  close(){
    let data = { 'refresh': false };
    this._viewCtrl.dismiss(data);
  }

  /**
   * Save the model
   */
  save(){
    let loader = this._loadingCtrl.create();
    loader.present();

    this.updateModelDataFromForm();

    let action;
    if(!this.model.bank_id){
      // Create
      action = this.bankService.create(this.model);
    }else{
      // Update
      action = this.bankService.update(this.model);
    }

    action.subscribe(jsonResponse => {
      loader.dismiss();

      // On Success
      if(jsonResponse.operation == "success"){
        // Close the page
        let data = { 'refresh': true,'model':jsonResponse.detail };
        this._viewCtrl.dismiss(data);
      }

      // On Failure
      if (jsonResponse.operation == "error") {
        var html = '';

        for (let i in jsonResponse.message) {
          for (let j of jsonResponse.message[i]) {
             html += j + '<br />';
          }
        }
        
        //failer text
        let prompt = this._alertCtrl.create({
          message: html,
          buttons: ["Ok"]
        });
        prompt.present();
      }
    });
  }
}



