import { Component } from '@angular/core';
import { NavController, LoadingController, ModalController, AlertController, ToastController } from 'ionic-angular';

// Pages
import { StaffViewPage } from '../staff-view/staff-view';
import { StaffFormPage } from '../staff-form/staff-form';

// Providers
import { StaffService } from '../../../../providers/logged-in/staff.service';

// Models
import { Staff } from '../../../../models/staff';

@Component({
  selector: 'page-staff-list',
  templateUrl: 'staff-list.html'
})
export class StaffListPage {

  public pageCount = 0;
  public currentPage = 1;
  public pages: number[] = [];

  public staff: Staff[];

  constructor(
    public navCtrl: NavController,
    public staffService: StaffService,
    private _modalCtrl: ModalController,
    private _loadingCtrl: LoadingController,
    private _alertCtrl: AlertController,
    private _toastCtrl: ToastController
  ) { }

  ionViewDidLoad() {
    this.loadData(this.currentPage);
  }

  loadData(page: number) {
    // Load list of staff
    let loader = this._loadingCtrl.create();
    loader.present();
    this.staffService.list(page).subscribe(response => {

      this.pageCount = response.headers.get('X-Pagination-Page-Count');
      this.currentPage = response.headers.get('X-Pagination-Current-Page');

      this.pages = [];

      for (var i = 1; i <= this.pageCount; i++) {
        this.pages.push(i);
      }

      //hide if no page = 1 

      if (this.pageCount == 1)
        this.pages = [];

      this.staff = response.json();
    },
      error => { },
      () => { loader.dismiss(); }
    );
  }

  /**
   * When its selected
   */
  rowSelected(model) {
    // Load Detail Page
    this.navCtrl.push(StaffViewPage, {
      'model': model
    });
  }

  /**
   * Loads the create page
   */
  create() {
    let modal = this._modalCtrl.create(StaffFormPage, {
      model: new Staff()
    });
    // Refresh List if required
    modal.onDidDismiss(data => {
      if (data) {
        if (data.refresh) {
          this.loadData(this.currentPage);
        }
      }
    });
    modal.present();
  }

  /**
   * Confirm password reset and send new password 
   * @param staffMember 
   */
  resetPassword(staffMember: Staff) {
    let confirm = this._alertCtrl.create({
      title: 'Confirm password reset',
      message: 'Do you want to send new password to staff?',
      buttons: [
        {
          text: 'Yes',
          handler: () => {
            this.sendNewPassword(staffMember);
          }
        },
        {
          text: 'No',
          role: 'cancel'
        }
      ]
    });
    confirm.present();
  }

  /**
   * Reset and email the staff a new password
   */
  sendNewPassword(staffMember: Staff) {
    let loader = this._loadingCtrl.create();
    loader.present();

    this.staffService.resetPassword(staffMember).subscribe(response => {
      loader.dismiss();

      if(response.operation == 'error')
      {
        let toast = this._toastCtrl.create({
          message: response.message,
          duration: 3000
        });
        
        toast.present();
      } 
      else 
      {
        let alert = this._alertCtrl.create({
            title: 'Reset Password',
            subTitle: 'New password sent to candidate',
            buttons: ['Okay']
          });
          alert.present();
      }      
    });
  }

  /**
   * Delete the provided model
   */
  delete(staff: Staff) {
    let loader = this._loadingCtrl.create();
    loader.present();
    let confirm = this._alertCtrl.create({
      title: 'Delete Staff?',
      message: 'Are you sure you want to delete this Staff?',
      buttons: [
        {
          text: 'Yes',
          handler: () => {
            this.staffService.delete(staff).subscribe(jsonResp => {
              loader.dismiss();

              if (jsonResp.operation == 'error') {
                let alert = this._alertCtrl.create({
                  title: 'Deletion Error!',
                  subTitle: jsonResp.message,
                  buttons: ['OK']
                });
                alert.present();
              }

              if (jsonResp.operation == 'success') {
                let toast = this._toastCtrl.create({
                  message: jsonResp.message,
                  duration: 3000
                });
                toast.present();
              }
              this.loadData(this.currentPage);
            });
          }
        },
        {
          text: 'No',
          handler: () => {
            this.loadData(this.currentPage);
            loader.dismiss();
          }
        }
      ]
    });
    confirm.present();
  }
}



